@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftAsync">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightAsync">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task MoveLeftAsync() => await OnMoveLeft.InvokeAsync(Task.Id);
    private async System.Threading.Tasks.Task MoveRightAsync() => await OnMoveRight.InvokeAsync(Task.Id);
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="SaveAsync" disabled="@saving">
                @(saving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
        @if (errorMessage is not null)
        {
            <div class="text-danger small mt-1">@errorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter] public string DefaultStatus { get; set; } = "To Do";
    [Parameter] public EventCallback<TaskItem> OnSaved { get; set; }
    [Parameter] public EventCallback OnCancelled { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? errorMessage;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async System.Threading.Tasks.Task SaveAsync()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnSaved.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async System.Threading.Tasks.Task Cancel() => await OnCancelled.InvokeAsync();
}

@* A single Kanban column: header with count, task cards, and an add-task toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@Status</strong>
            <span class="badge bg-secondary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="HandleMoveLeftAsync"
                          OnMoveRight="HandleMoveRightAsync" />
            }

            @if (showAddForm)
            {
                <AddTaskForm DefaultStatus="@Status"
                             OnSaved="HandleTaskCreatedAsync"
                             OnCancelled="HideAddForm" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="ShowAddForm">+ Add Task</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;

    private void ShowAddForm() => showAddForm = true;
    private void HideAddForm() => showAddForm = false;

    private async System.Threading.Tasks.Task HandleMoveLeftAsync(int taskId) =>
        await OnMoveLeft.InvokeAsync(taskId);

    private async System.Threading.Tasks.Task HandleMoveRightAsync(int taskId) =>
        await OnMoveRight.InvokeAsync(taskId);

    private async System.Threading.Tasks.Task HandleTaskCreatedAsync(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title…"
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async System.Threading.Tasks.Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

