+        <div class="card-body overflow-auto" style="max-height: 70vh;">
+            @foreach (var task in Tasks)
+            {
+                <TaskCard Task="task"
+                          ShowMoveLeft="ShowMoveLeft"
+                          ShowMoveRight="ShowMoveRight"
+                          OnMoveLeft="HandleMoveLeftAsync"
+                          OnMoveRight="HandleMoveRightAsync" />
+            }
+
+            @if (showAddForm)
+            {
+                <AddTaskForm DefaultStatus="@Status"
+                             OnSaved="HandleTaskCreatedAsync"
+                             OnCancelled="HideAddForm" />
+            }
+            else
+            {
+                <button class="btn btn-outline-primary btn-sm w-100" @onclick="ShowAddForm">+ Add Task</button>
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public string Status { get; set; } = "";
+    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
+    [Parameter] public bool ShowMoveLeft { get; set; }
+    [Parameter] public bool ShowMoveRight { get; set; }
+    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
+    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
+    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
+
+    private bool showAddForm;
+
+    private void ShowAddForm() => showAddForm = true;
+    private void HideAddForm() => showAddForm = false;
+
+    private async System.Threading.Tasks.Task HandleMoveLeftAsync(int taskId) =>
+        await OnMoveLeft.InvokeAsync(taskId);
+
+    private async System.Threading.Tasks.Task HandleMoveRightAsync(int taskId) =>
+        await OnMoveRight.InvokeAsync(taskId);
+
+    private async System.Threading.Tasks.Task HandleTaskCreatedAsync(TaskItem task)
+    {
+        showAddForm = false;
+        await OnTaskCreated.InvokeAsync(task);
+    }
+}
+

