@page "/board"
@rendermode InteractiveServer
@using sv_6f04153da4c74a44b84efbf3f31d4c1c.Components.Pages.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks…</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn Status="To Do"
                      Tasks="FilteredByStatus("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="@(id => MoveTaskAsync(id, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Status="In Progress"
                      Tasks="FilteredByStatus("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="@(id => MoveTaskAsync(id, "To Do"))"
                      OnMoveRight="@(id => MoveTaskAsync(id, "Done"))"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Status="Done"
                      Tasks="FilteredByStatus("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="@(id => MoveTaskAsync(id, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> FilteredByStatus(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string term) => searchTerm = term;

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state to reflect the move
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks
                    .Select(t => t.Id == taskId ? t with { Status = newStatus } : t)
                    .ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

